1	import React, { useState } from "react";
2	import type { DevProject, Phase, ProjectStatus, PhaseStatus } from "../../worker/types";
3	import ProjectHeader from "./ProjectHeader";
4	
5	// Placeholder data — replace with real plugin state API calls
6	const MOCK_PROJECTS: DevProject[] = [];
7	
8	const STATUS_COLORS: Record<ProjectStatus, { bg: string; text: string }> = {
9	  Draft:    { bg: "#f3f4f6", text: "#6b7280" },
10	  Active:   { bg: "#dcfce7", text: "#16a34a" },
11	  Blocked:  { bg: "#fee2e2", text: "#dc2626" },
12	  Archived: { bg: "#f3f4f6", text: "#9ca3af" },
13	};
14	
15	const PHASE_STATUS_LABELS: Record<PhaseStatus, string> = {
16	  DraftSpec:                "Draft Spec",
17	  SpecApproved:             "Spec Approved",
18	  PRDAttached:              "PRD Attached",
19	  ReadyForBuild:            "Ready for Build",
20	  Accepted:                 "Accepted",
21	  ReworkRequired:           "Rework Required",
22	  Closed:                   "Closed",
23	};
24	
25	function StatusBadge({ status }: { status: ProjectStatus }) {
26	  const colors = STATUS_COLORS[status];
27	  return (
28	    <span style={{
29	      padding: "2px 10px",
30	      borderRadius: "12px",
31	      fontSize: "12px",
32	      fontWeight: 600,
33	      backgroundColor: colors.bg,
34	      color: colors.text,
35	    }}>
36	      {status}
37	    </span>
38	  );
39	}
40	
41	function PhaseList({ phases }: { phases: Phase[] }) {
42	  if (phases.length === 0) {
43	    return (
44	      <div style={{ padding: "24px", textAlign: "center", color: "#9ca3af", fontSize: "14px" }}>
45	        No phases yet. Add a phase to get started.
46	      </div>
47	    );
48	  }
49	
50	  return (
51	    <div style={{ padding: "12px 16px" }}>
52	      {phases.map((phase) => (
53	        <div
54	          key={phase.id}
55	          style={{
56	            padding: "12px",
57	            border: "1px solid #e5e7eb",
58	            borderRadius: "8px",
59	            marginBottom: "8px",
60	            backgroundColor: "#fff",
61	          }}
62	        >
63	          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
64	            <span style={{ fontWeight: 600, fontSize: "14px", color: "#111827" }}>
65	              Phase {phase.phaseNumber}: {phase.title}
66	            </span>
67	            <span style={{
68	              fontSize: "12px",
69	              padding: "2px 8px",
70	              borderRadius: "12px",
71	              backgroundColor: "#eff6ff",
72	              color: "#1d4ed8",
73	              fontWeight: 500,
74	            }}>
75	              {PHASE_STATUS_LABELS[phase.status]}
76	            </span>
77	          </div>
78	          {phase.objective && (
79	            <p style={{ margin: "6px 0 0", fontSize: "13px", color: "#6b7280" }}>
80	              {phase.objective}
81	            </p>
82	          )}
83	        </div>
84	      ))}
85	    </div>
86	  );
87	}
88	
89	export default function DepartmentView() {
90	  const [projects, setProjects] = useState<DevProject[]>(MOCK_PROJECTS);
91	  const [selectedProject, setSelectedProject] = useState<DevProject | null>(null);
92	  // In a real implementation, phases would be loaded per project
93	  const [phases] = useState<Phase[]>([]);
94	
95	  const handleCreateProject = () => {
96	    const newProject: DevProject = {
97	      id: `proj-${Date.now()}`,
98	      name: "New Project",
99	      objective: "",
100	      owner: "",
101	      status: "Draft",
102	      activePhaseId: null,
103	      roadmapSummary: "",
104	      createdAt: new Date().toISOString(),
105	      updatedAt: new Date().toISOString(),
106	    };
107	    setProjects((prev) => [...prev, newProject]);
108	    setSelectedProject(newProject);
109	  };
110	
111	  const handleSaveProject = (updates: Partial<DevProject>) => {
112	    if (!selectedProject) return;
113	    const updated = { ...selectedProject, ...updates, updatedAt: new Date().toISOString() };
114	    setProjects((prev) => prev.map((p) => (p.id === updated.id ? updated : p)));
115	    setSelectedProject(updated);
116	  };
117	
118	  // Detail view
119	  if (selectedProject) {
120	    return (
121	      <div style={{ fontFamily: "system-ui, sans-serif", height: "100%" }}>
122	        <div style={{ padding: "10px 16px", borderBottom: "1px solid #e5e7eb" }}>
123	          <button
124	            onClick={() => setSelectedProject(null)}
125	            style={{
126	              background: "none",
127	              border: "none",
128	              cursor: "pointer",
129	              color: "#2563eb",
130	              fontSize: "14px",
131	              padding: 0,
132	              display: "flex",
133	              alignItems: "center",
134	              gap: "4px",
135	            }}
136	          >
137	            ← Back to Projects
138	          </button>
139	        </div>
140	
141	        <ProjectHeader
142	          project={selectedProject}
143	          phases={phases}
144	          onSave={handleSaveProject}
145	          onCancel={() => setSelectedProject(null)}
146	        />
147	
148	        <div style={{ padding: "12px 16px 4px", fontWeight: 600, fontSize: "13px", color: "#374151" }}>
149	          Phases
150	        </div>
151	        <PhaseList phases={phases} />
152	      </div>
153	    );
154	  }
155	
156	  // List view
157	  return (
158	    <div style={{ fontFamily: "system-ui, sans-serif", height: "100%" }}>
159	      <div style={{
160	        padding: "12px 16px",
161	        borderBottom: "1px solid #e5e7eb",
162	        display: "flex",
163	        justifyContent: "space-between",
164	        alignItems: "center",
165	      }}>
166	        <span style={{ fontWeight: 700, fontSize: "16px", color: "#111827" }}>
167	          Development Department
168	        </span>
169	        <button
170	          onClick={handleCreateProject}
171	          style={{
172	            padding: "6px 14px",
173	            backgroundColor: "#2563eb",
174	            color: "#fff",
175	            border: "none",
176	            borderRadius: "6px",
177	            cursor: "pointer",
178	            fontSize: "13px",
179	            fontWeight: 500,
180	          }}
181	        >
182	          + Create Project
183	        </button>
184	      </div>
185	
186	      {projects.length === 0 ? (
187	        <div style={{ padding: "32px 16px", textAlign: "center", color: "#9ca3af", fontSize: "14px" }}>
188	          No projects yet. Click "Create Project" to get started.
189	        </div>
190	      ) : (
191	        <div style={{ padding: "8px" }}>
192	          {projects.map((project) => (
193	            <div
194	              key={project.id}
195	              onClick={() => setSelectedProject(project)}
196	              style={{
197	                padding: "12px",
198	                border: "1px solid #e5e7eb",
199	                borderRadius: "8px",
200	                marginBottom: "6px",
201	                cursor: "pointer",
